const fs = require('fs')
const path = require('path')

function ensureDir(p) {
  const dir = path.dirname(p)
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true })
}

const files = [
  'src/app/api/inquiry/route.ts',
  'src/app/feed/[id]/FeedPostCTA.tsx',
  'src/app/client/inbox/page.tsx',
  'src/app/client/inbox/ClientInboxClient.tsx',
  'src/app/dashboard/BuilderDashboardClient.tsx',
  'src/app/messages/page.tsx',
  'src/lib/user.ts',
  'src/lib/types.ts',
  'src/app/components/FooterBar.tsx',
]

// Base64-encoded file contents
const contents = {
  'src/app/api/inquiry/route.ts': '',
  'src/app/feed/[id]/FeedPostCTA.tsx': '',
  'src/app/client/inbox/page.tsx': '',
  'src/app/client/inbox/ClientInboxClient.tsx': '',
  'src/app/dashboard/BuilderDashboardClient.tsx': '',
  'src/app/messages/page.tsx': '',
  'src/lib/user.ts': '',
  'src/lib/types.ts': '',
  'src/app/components/FooterBar.tsx': '',
}

let ok = 0
let fail = 0
for (const [relPath, encoded] of Object.entries(contents)) {
  try {
    ensureDir(relPath)
    const content = Buffer.from(encoded, 'base64').toString('utf8')
    fs.writeFileSync(relPath, content)
    console.log('✓', relPath)
    ok++
  } catch (e) {
    console.error('✗', relPath, e.message)
    fail++
  }
}
console.log(`\nDone: ${ok} written, ${fail} failed`)

// Also write the feed post page via separate script (needs [id] dir)
const feedContent = fs.readFileSync('src/app/feed/[id]/FeedPostCTA.tsx', 'utf8')
console.log('\nFeedPostCTA size:', feedContent.length, 'bytes ✓')
